// Phase 2 — Discover clubs for one federation (proof: Poland deterministic extractor).
// Auth via the upstream "PB Auth" node (Custom Auth credential); token reused here.
// Find-or-create clubs by dedup_key, then update the federation. See specs/club-discovery.md.

const PB_URL = ($('Config').first().json.pbUrl || '').replace(/\/+$/, '');
const token = $('PB Auth').first().json.token;
if (!token) throw new Error('No PocketBase token — check the "PocketBase admin" credential on PB Auth.');
const pbH = { Authorization: token };

const body = ($('Webhook').first().json.body) || {};
const fedId = body.id;
if (!fedId) throw new Error('Webhook body must include the federation record id.');

const fed = await this.helpers.httpRequest({
  method: 'GET', url: PB_URL + '/api/collections/federations/records/' + fedId, headers: pbH, json: true,
});
const code = String(fed.fivb_code || body.fivb_code || '').toUpperCase();
const country = fed.country || '';
const now = new Date().toISOString();
const normUrl = (u) => { u = (u || '').trim().replace(/^https?:\/\//i, ''); if (!u) return ''; if (/[\s,]/.test(u) || !u.includes('.')) return ''; return 'https://' + u; };

// --- extractor registry (proof covers Poland; others -> needs_review) ---
if (code !== 'POL') {
  await this.helpers.httpRequest({
    method: 'PATCH', url: PB_URL + '/api/collections/federations/records/' + fedId, headers: pbH,
    body: { status: 'needs_review', notes: 'no club extractor implemented yet (proof = Poland only)' }, json: true,
  });
  return [{ json: { ok: false, federation: code, note: 'no extractor for ' + code + ' yet' } }];
}

// Poland: open JSON API, all clubs in one GET.
const SOURCE = 'https://pzps-rejestracja.pl/klub/getList';
const res = await this.helpers.httpRequest({
  method: 'GET', url: SOURCE, headers: { 'User-Agent': 'Mozilla/5.0 (compatible; leblovina-n8n)' }, json: true,
});
const all = (res && res.data) ? res.data : (Array.isArray(res) ? res : []);
const rows = all.filter((r) =>
  String(r.aktywny) === '1' && !r.deleted_at && r.nazwa && !/^[-\s]*$/.test(String(r.nazwa)));

const findByKey = async (key) => {
  const r = await this.helpers.httpRequest({
    method: 'GET', url: PB_URL + '/api/collections/clubs/records',
    qs: { filter: "(dedup_key='" + key + "')", perPage: 1 }, headers: pbH, json: true,
  });
  return (r.items && r.items[0]) || null;
};

let created = 0, updated = 0, failed = 0;
const errors = [];
for (const r of rows) {
  const dedup = 'POL:' + r.id;
  const website = normUrl(r.www);
  const payload = {
    federation: fedId, name: String(r.nazwa).trim(), country,
    region: (r.wzps_nazwa || '').trim(), city: (r.miasto || '').trim(),
    website_url: website, website_source: website ? 'official_list' : 'none',
    source_url: SOURCE, source_club_id: String(r.id), dedup_key: dedup, last_scraped: now,
  };
  try {
    try {
      await this.helpers.httpRequest({
        method: 'POST', url: PB_URL + '/api/collections/clubs/records', headers: pbH,
        body: Object.assign({ status: 'new' }, payload), json: true,
      });
      created++;
    } catch (e) {
      const ex = await findByKey(dedup);
      if (ex) {
        await this.helpers.httpRequest({
          method: 'PATCH', url: PB_URL + '/api/collections/clubs/records/' + ex.id, headers: pbH, body: payload, json: true,
        });
        updated++;
      } else { throw e; }
    }
  } catch (e) {
    failed++;
    if (errors.length < 10) errors.push({ key: dedup, message: (e && e.message) || String(e) });
  }
}

const fedStatus = failed === 0 ? 'scraped' : 'error';
await this.helpers.httpRequest({
  method: 'PATCH', url: PB_URL + '/api/collections/federations/records/' + fedId, headers: pbH,
  body: {
    club_directory_url: SOURCE,
    directory_urls: [{ url: SOURCE, region: 'national', extraction_method: 'api_endpoint' }],
    extraction_method: 'api_endpoint', status: fedStatus, last_scraped: now,
  }, json: true,
});

return [{ json: { ok: failed === 0, federation: 'POL', total: rows.length, created, updated, failed, errors } }];
